-- FORMAT after UNION ALL
SELECT * FROM test1
UNION ALL
SELECT * FROM test2
FORMAT CSV;

-- INTO OUTFILE after UNION ALL
SELECT * FROM test1
UNION ALL
SELECT * FROM test2
INTO OUTFILE 'output.csv' FORMAT CSV;

